package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  // Use Object for the mock type instead of RecordHelper, to avoid compilation error
  private static Object mockRecordHelper;

  static class TestRecord {
    // A record class requires Java 16+, but since we can't guarantee environment,
    // we will mock behavior instead.
  }

  static class NotRecord {
  }

  interface RecordHelperInterface {
    boolean isRecord(Class<?> raw);
  }

  @BeforeAll
  static void setup() throws Exception {
    // Create a mock of the internal RecordHelper class via reflection
    Class<?> recordHelperClass = Class.forName("com.google.gson.internal.reflect.ReflectionHelper$RecordHelper");
    mockRecordHelper = mock(recordHelperClass);

    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void testIsRecordTrue() throws Exception {
    // Use reflection to get the isRecord method
    var isRecordMethod = mockRecordHelper.getClass().getMethod("isRecord", Class.class);

    // Use Mockito to stub isRecord method on mockRecordHelper via Answer
    doAnswer(invocation -> {
      Class<?> arg = invocation.getArgument(0);
      return arg == String.class;
    }).when(mockRecordHelper).getClass()
      .getMethod("isRecord", Class.class)
      .invoke(mockRecordHelper, String.class);

    // The above doesn't work because Mockito cannot stub via reflection invoke directly.
    // Instead, use Mockito's doAnswer on mockRecordHelper with a spy proxy.

    // So create a proxy implementing the RecordHelper interface to delegate calls to mockRecordHelper
    // But since RecordHelper is private, create a dynamic proxy with interface matching isRecord method

    // Instead, cast mockRecordHelper to RecordHelperInterface via Proxy

    RecordHelperInterface proxy = (RecordHelperInterface) java.lang.reflect.Proxy.newProxyInstance(
        RecordHelperInterface.class.getClassLoader(),
        new Class<?>[] { RecordHelperInterface.class },
        (proxyObj, method, args) -> {
          if ("isRecord".equals(method.getName()) && args.length == 1) {
            Class<?> arg = (Class<?>) args[0];
            return arg == String.class;
          }
          return method.invoke(mockRecordHelper, args);
        });

    // Replace RECORD_HELPER with proxy
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, proxy);

    // Test ReflectionHelper.isRecord returns true for String.class
    assertTrue(ReflectionHelper.isRecord(String.class));
  }

  @Test
  void testIsRecordFalse() throws Exception {
    // Similar proxy for false case
    RecordHelperInterface proxy = (RecordHelperInterface) java.lang.reflect.Proxy.newProxyInstance(
        RecordHelperInterface.class.getClassLoader(),
        new Class<?>[] { RecordHelperInterface.class },
        (proxyObj, method, args) -> {
          if ("isRecord".equals(method.getName()) && args.length == 1) {
            Class<?> arg = (Class<?>) args[0];
            return false;
          }
          return method.invoke(mockRecordHelper, args);
        });

    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, proxy);

    // Test ReflectionHelper.isRecord returns false for NotRecord.class
    assertFalse(ReflectionHelper.isRecord(NotRecord.class));
  }
}
